cd /tmp/sv-23826fe089b64a5bbea32b6b2d7d21cd/moderate-version-conflicts && dotnet list package --format json 2>/dev/null | python3 -m json.tool > after-cpm-packages.json && python3 -c "
import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def pkg_map(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-2]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                result[(name, pkg['id'])] = (pkg['requestedVersion'], pkg['resolvedVersion'])
    return result

b = pkg_map(baseline)
a = pkg_map(after)
changes = []
unchanged = []
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    bv = b.get(key)
    av = a.get(key)
    if bv and av and bv == av:
        unchanged.append((key[0], key[1], bv[1]))
    else:
        changes.append((key[0], key[1], bv, av))

print('=== CHANGES ===')
for proj, pkg, bv, av in changes:
    print(f'{proj}/{pkg}: {bv} -> {av}')
print()
print('=== UNCHANGED ===')
for proj, pkg, ver in unchanged:
    print(f'{proj}/{pkg}: {ver}')
"

